mistake_patterns.detection_sql:
SELECT COUNT(*) FROM (
  SELECT product_name, revenue, revenue / SUM(revenue) AS pct FROM sales GROUP BY 1, 2
) LIMIT 1

SELECT COUNT(*) FROM orders WHERE id IN (
  SELECT id FROM (
    SELECT id, ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY order_date DESC) AS rn
    FROM orders
  ) WHERE rn = 1
) -- count should match unique customers
